   342→### 7. Update StopOrchestrator.hook.ts
   343→**File**: `.claude/hooks/StopOrchestrator.hook.ts`
   344→
   345→**Issue**: Process termination, signal handling
   346→
   347→**Solution:**
   348→```typescript
   349→import { spawnSync } from 'child_process';
   350→import { PLATFORM } from './lib/paths';
   351→
   352→export function stopOrchestrator(orchestratorId: string): void {
   353→  if (PLATFORM === 'win32') {
   354→    // Windows: use taskkill
   355→    spawnSync('taskkill', ['/F', '/PID', orchestratorId], {
   356→      shell: true
   357→    });
   358→  } else {
   359→    // Unix: use kill
   360→    spawnSync('kill', ['-9', orchestratorId]);
   361→  }
   362→}
   363→
   364→export function findProcessByName(name: string): number[] {
   365→  let result: string;
   366→
   367→  if (PLATFORM === 'win32') {
   368→    // Windows PowerShell
   369→    result = spawnSync('powershell', [
   370→      '-Command',
   371→      `Get-Process -Name "${name}" -ErrorAction SilentlyContinue | Select-Object -ExpandProperty Id`
   372→    ], { encoding: 'utf8' }).stdout;
   373→  } else {
   374→    // Unix: pgrep or ps
   375→    result = spawnSync('pgrep', [name], { encoding: 'utf8' }).stdout;
   376→  }
   377→
   378→  return result
   379→    .trim()
   380→    .split('\n')
   381→    .filter(Boolean)
   382→    .map(Number);
   383→}
   384→```
