    99→// Cross-platform file search
   100→function findExecutableFiles(dir: string, pattern: string): string[] {
   101→  const results: string[] = [];
   102→
   103→  function walk(currentPath: string) {
   104→    const files = fs.readdirSync(currentPath);
   105→    for (const file of files) {
   106→      const fullPath = path.join(currentPath, file);
   107→      const stat = fs.statSync(fullPath);
   108→
   109→      if (stat.isDirectory()) {
   110→        walk(fullPath);
   111→      } else if (file.match(pattern)) {
   112→        results.push(fullPath);
   113→      }
   114→    }
   115→  }
   116→
   117→  walk(dir);
   118→  return results;
   119→}
