    76→async function prompt(question: string, defaultValue?: string): Promise<string> {
    77→  const displayDefault = defaultValue ? ` ${c.gray}[${defaultValue}]${c.reset}` : '';
    78→  const rl = createReadline();
    79→
    80→  return new Promise((resolve) => {
    81→    rl.question(`  ${question}${displayDefault}: `, (answer) => {
    82→      rl.close();
    83→      resolve(answer.trim() || defaultValue || '');
    84→    });
    85→  });
    86→}
