   425→
   426→  // Check settings.json
   427→  const settingsPath = join(CLAUDE_DIR, 'settings.json');
   428→  if (existsSync(settingsPath)) {
   429→    try {
   430→      const settings = JSON.parse(readFileSync(settingsPath, 'utf-8'));
   431→      if (settings.principal?.name && settings.daidentity?.name) {
   432→        results.push(`${c.green}✓${c.reset} settings.json valid`);
   433→      } else {
   434→        results.push(`${c.red}✗${c.reset} settings.json missing required fields`);
   435→        passed = false;
   436→      }
   437→    } catch (e) {
   438→      results.push(`${c.red}✗${c.reset} settings.json invalid JSON`);
   439→      passed = false;
   440→    }
   441→  } else {
   442→    results.push(`${c.red}✗${c.reset} settings.json not found`);
   443→    passed = false;
   444→  }
   445→
   446→  // Check directories
