     1→/**
     2→ * UpdateCounts.ts - Update settings.json with fresh system counts
     3→ *
     4→ * PURPOSE:
     5→ * Updates the counts section of settings.json at the end of each session.
     6→ * Banner and statusline then read from settings.json (instant, no execution).
     7→ *
     8→ * ARCHITECTURE:
     9→ * Stop hook → UpdateCounts → settings.json
    10→ * Session start → Banner reads settings.json (instant)
    11→ * Session start → Statusline reads settings.json (instant)
    12→ *
    13→ * This design ensures:
    14→ * - No spawning/execution at session start
    15→ * - Counts are always available (no waiting)
    16→ * - Single source of truth in settings.json
    17→ */
    18→
    19→import { readFileSync, writeFileSync, readdirSync, existsSync, statSync } from 'fs';
    20→import { join } from 'path';
    21→import { getPaiDir, getSettingsPath } from '../lib/paths';
    22→
    23→interface Counts {
    24→  skills: number;
    25→  workflows: number;
    26→  hooks: number;
    27→  signals: number;
    28→  files: number;
    29→  updatedAt: string;
    30→}
    31→
    32→/**
    33→ * Count files matching criteria recursively
    34→ */
    35→function countFilesRecursive(dir: string, extension?: string): number {
    36→  let count = 0;
    37→  try {
    38→    for (const entry of readdirSync(dir, { withFileTypes: true })) {
    39→      const fullPath = join(dir, entry.name);
    40→      if (entry.isDirectory()) {
    41→        count += countFilesRecursive(fullPath, extension);
    42→      } else if (entry.isFile()) {
    43→        if (!extension || entry.name.endsWith(extension)) {
    44→          count++;
    45→        }
    46→      }
    47→    }
    48→  } catch {
    49→    // Directory doesn't exist or not readable
    50→  }
    51→  return count;
    52→}
    53→
    54→/**
    55→ * Count .md files inside any Workflows directory
    56→ */
    57→function countWorkflowFiles(dir: string): number {
    58→  let count = 0;
    59→  try {
    60→    for (const entry of readdirSync(dir, { withFileTypes: true })) {
    61→      const fullPath = join(dir, entry.name);
    62→      if (entry.isDirectory()) {
    63→        if (entry.name.toLowerCase() === 'workflows') {
    64→          count += countFilesRecursive(fullPath, '.md');
    65→        } else {
    66→          count += countWorkflowFiles(fullPath);
    67→        }
    68→      }
    69→    }
    70→  } catch {
    71→    // Directory doesn't exist or not readable
    72→  }
    73→  return count;
    74→}
    75→
    76→/**
    77→ * Count skills (directories with SKILL.md file)
    78→ */
    79→function countSkills(paiDir: string): number {
    80→  let count = 0;
    81→  const skillsDir = join(paiDir, 'skills');
    82→  try {
    83→    for (const entry of readdirSync(skillsDir, { withFileTypes: true })) {
    84→      if (entry.isDirectory()) {
    85→        const skillFile = join(skillsDir, entry.name, 'SKILL.md');
    86→        if (existsSync(skillFile)) {
    87→          count++;
    88→        }
    89→      }
    90→    }
    91→  } catch {
    92→    // skills directory doesn't exist
    93→  }
    94→  return count;
    95→}
    96→
    97→/**
    98→ * Count hooks (.ts files in hooks/ at depth 1)
    99→ */
   100→function countHooks(paiDir: string): number {
   101→  let count = 0;
   102→  const hooksDir = join(paiDir, 'hooks');
   103→  try {
   104→    for (const entry of readdirSync(hooksDir, { withFileTypes: true })) {
   105→      if (entry.isFile() && entry.name.endsWith('.ts')) {
   106→        count++;
   107→      }
   108→    }
   109→  } catch {
   110→    // hooks directory doesn't exist
   111→  }
   112→  return count;
   113→}
   114→
   115→/**
   116→ * Count non-empty lines in a JSONL file (signals = rating entries)
   117→ */
   118→function countRatingsLines(filePath: string): number {
   119→  try {
   120→    if (!existsSync(filePath) || !statSync(filePath).isFile()) return 0;
   121→    return readFileSync(filePath, 'utf-8').split('\n').filter(l => l.trim()).length;
   122→  } catch {
   123→    return 0;
   124→  }
   125→}
   126→
   127→/**
   128→ * Get all counts
   129→ */
   130→function getCounts(paiDir: string): Counts {
   131→  return {
   132→    skills: countSkills(paiDir),
   133→    workflows: countWorkflowFiles(join(paiDir, 'skills')),
   134→    hooks: countHooks(paiDir),
   135→    signals: countRatingsLines(join(paiDir, 'MEMORY/LEARNING/SIGNALS/ratings.jsonl')),
   136→    files: countFilesRecursive(join(paiDir, 'skills/PAI/USER')),
   137→    updatedAt: new Date().toISOString(),
   138→  };
   139→}
   140→
   141→/**
   142→ * Handler called by StopOrchestrator
   143→ */
   144→export async function handleUpdateCounts(): Promise<void> {
   145→  const paiDir = getPaiDir();
   146→  const settingsPath = getSettingsPath();
   147→
   148→  try {
   149→    // Get fresh counts
   150→    const counts = getCounts(paiDir);
   151→
   152→    // Read current settings
   153→    const settings = JSON.parse(readFileSync(settingsPath, 'utf-8'));
   154→
   155→    // Update counts section
   156→    settings.counts = counts;
   157→
   158→    // Write back
   159→    writeFileSync(settingsPath, JSON.stringify(settings, null, 2) + '\n');
   160→
   161→    console.error(`[UpdateCounts] Updated settings.json: ${counts.skills} skills, ${counts.workflows} workflows, ${counts.hooks} hooks, ${counts.signals} signals, ${counts.files} files`);
   162→  } catch (error) {
   163→    console.error('[UpdateCounts] Failed to update counts:', error);
   164→    // Non-fatal - don't throw, let other handlers continue
   165→  }
   166→}
   167→
   168→// Allow running standalone to seed initial counts
   169→if (import.meta.main) {
   170→  handleUpdateCounts().then(() => process.exit(0));
   171→}
