    57→    }
    58→
    59→    const tabState: TabTitleState = {
    60→      title,
    61→      rawTitle,
    62→      timestamp: getISOTimestamp(),
    63→      state,
    64→    };
    65→
    66→    writeFileSync(TAB_STATE_PATH, JSON.stringify(tabState, null, 2), 'utf-8');
    67→    console.error(`[TabState] Persisted title: "${rawTitle}"`);
    68→  } catch (error) {
    69→    console.error('[TabState] Failed to persist title:', error);
    70→  }
    71→}
    72→
    73→const COMPLETION_PROMPT = `Create a 3-5 word COMPLETE SENTENCE describing what was done.
    74→
    75→FORMAT: "[Specific subject] [past participle]."
    76→The subject MUST come first so tabs are distinguishable.
    77→
    78→GOOD (specific subjects):
    79→- "Auth bug fixed."
    80→- "Hook validation updated."
    81→- "Tab title logic simplified."
    82→- "Context filtering improved."
    83→- "Letter to manager drafted."
    84→
    85→BAD — NEVER USE GENERIC SUBJECTS:
    86→- "Task completed." (generic — WHAT task?)
    87→- "Task completion described." (generic meta-description)
    88→- "Work finished." (generic)
    89→- "Request handled." (generic)
    90→- "Response generated." (meta)
    91→
    92→BAD — fragments:
    93→- "Fixed." (too vague)
    94→- "Updated the" (incomplete)
    95→- "Done with the" (fragment)
    96→
    97→RULES:
    98→1. 3-5 words, COMPLETE sentence
    99→2. SPECIFIC subject FIRST (name the actual thing), then past participle
   100→3. NEVER use "task", "work", "request", "response", "completion" as subjects
   101→4. End with period
   102→
   103→Output ONLY the sentence. Nothing else.`;
   104→
   105→// Generic subjects that provide zero information about what was actually done
   106→const GENERIC_SUBJECTS = [
   107→  'task', 'work', 'request', 'response', 'completion',
   108→  'job', 'item', 'thing', 'action', 'operation', 'process',
   109→];
   110→
   111→/**
   112→ * Check if a completion summary uses a generic subject instead of a specific one.
   113→ * "Task completed." is useless. "Auth bug fixed." is useful.
   114→ */
   115→function hasGenericSubject(summary: string): boolean {
   116→  const content = summary.replace(/\.$/, '').trim().toLowerCase();
   117→  const firstWord = content.split(/\s+/)[0];
   118→  return GENERIC_SUBJECTS.includes(firstWord);
   119→}
   120→
   121→/**
   122→ * Generate a proper 3-5 word completion summary using inference.
   123→ * Subject comes first for tab distinguishability.
   124→ * Validates output to reject generic summaries like "Task completed."
   125→ */
   126→async function generateCompletionSummary(voiceLine: string): Promise<string> {
   127→  try {
   128→    const result = await inference({
   129→      systemPrompt: COMPLETION_PROMPT,
   130→      userPrompt: voiceLine.slice(0, 500),
   131→      timeout: 20000,
   132→      level: 'standard',  // Sonnet for better subject extraction
   133→    });
   134→
   135→    if (result.success && result.output) {
   136→      let summary = result.output.replace(/^["']|["']$/g, '').trim();
   137→      const words = summary.split(/\s+/).slice(0, 5);
   138→      summary = words.join(' ');
   139→      if (!summary.endsWith('.')) summary += '.';
   140→
   141→      // Reject generic subjects — "Task completed." tells you nothing
   142→      if (hasGenericSubject(summary)) {
   143→        console.error(`[TabState] Rejected generic summary: "${summary}"`);
   144→        // Try to extract something specific from the voice line itself
   145→        const fallback = extractSpecificSubject(voiceLine);
   146→        return fallback;
   147→      }
   148→
   149→      return summary;
   150→    }
   151→  } catch (error) {
   152→    console.error('[TabState] Inference failed:', error);
   153→  }
   154→  return getTabFallback('end');
   155→}
   156→
   157→/**
   158→ * Extract a specific subject from the voice line when inference produces garbage.
   159→ * Takes the first few meaningful words from the voice line as a fallback.
   160→ */
   161→function extractSpecificSubject(voiceLine: string): string {
   162→  // Strip common prefixes like "Done.", "Kai:", etc.
   163→  const daName = getDAName();
   164→  let cleaned = voiceLine
   165→    .replace(new RegExp(`^(Done\\.?\\s*|${daName}:\\s*|I've\\s+|I\\s+)`, 'i'), '')
   166→    .trim();
   167→
   168→  if (!cleaned || cleaned.length < 3) return getTabFallback('end');
   169→
   170→  // Take first 4 meaningful words
   171→  const words = cleaned.split(/\s+/).slice(0, 4);
   172→  let result = words.join(' ');
   173→  // Clean trailing punctuation and add period
   174→  result = result.replace(/[,;:!?\-]+$/, '').trim();
   175→  if (!result.endsWith('.')) result += '.';
   176→  return result;
   177→}
   178→
   179→/**
   180→ * Handle tab state update with pre-parsed transcript data.
   181→ */
   182→export async function handleTabState(parsed: ParsedTranscript): Promise<void> {
   183→  let plainCompletion = parsed.plainCompletion;
   184→
   185→  // Validate completion
   186→  if (!isValidVoiceCompletion(plainCompletion)) {
   187→    console.error(`[TabState] Invalid completion: "${plainCompletion.slice(0, 50)}..."`);
   188→    plainCompletion = getTabFallback('end');
   189→  }
   190→
   191→  try {
   192→    const state: ResponseState = parsed.responseState;
   193→    const stateColor = TAB_COLORS[state];
   194→
   195→    // Use inference to generate proper completion summary
   196→    const shortTitle = await generateCompletionSummary(plainCompletion);
   197→
   198→    // Simple checkmark for completion - color indicates success vs error
   199→    const tabTitle = `✓${shortTitle}`;
   200→
   201→    console.error(`[TabState] State: ${state}, Title: "${tabTitle}"`);
   202→
   203→    // Persist title for recovery after compaction/restart
   204→    persistTabTitle(tabTitle, shortTitle, state);
   205→
   206→    // Set tab colors: active tab always dark blue, inactive shows state color
   207→    await Bun.$`kitten @ set-tab-color --self active_bg=${ACTIVE_TAB_COLOR} active_fg=${ACTIVE_TEXT_COLOR} inactive_bg=${stateColor} inactive_fg=${INACTIVE_TEXT_COLOR}`;
   208→
   209→    // Set tab title
   210→    await Bun.$`kitty @ set-tab-title ${tabTitle}`;
   211→  } catch (error) {
   212→    console.error('[TabState] Failed to update Kitty tab:', error);
   213→  }
   214→}
