     2→ * Observability Integration
     3→ * Sends hook events to the Agent Visibility Dashboard at localhost:4000
     4→ *
     5→ * Dashboard: https://github.com/disler/claude-code-hooks-multi-agent-observability
     6→ * Server runs at: localhost:4000
     7→ * Client dashboard: localhost:5173
     8→ */
     9→
    10→export interface ObservabilityEvent {
    11→  source_app: string;
    12→  session_id: string;
    13→  hook_event_type: 'PreToolUse' | 'PostToolUse' | 'UserPromptSubmit' | 'Notification' | 'Stop' | 'SubagentStop' | 'SessionStart' | 'SessionEnd' | 'PreCompact';
    14→  timestamp: string;
    15→  transcript_path?: string;
    16→  summary?: string;
    17→  tool_name?: string;
