    19→  tool_output?: any;
    20→  agent_type?: string;
    21→  model?: string;
    22→  [key: string]: any;
    23→}
    24→
    25→/**
    26→ * Send event to observability dashboard
    27→ * Fails silently if dashboard is not running - doesn't block hook execution
    28→ */
    29→export async function sendEventToObservability(event: ObservabilityEvent): Promise<void> {
    30→  try {
    31→    const response = await fetch('http://localhost:4000/events', {
    32→      method: 'POST',
    33→      headers: {
    34→        'Content-Type': 'application/json',
    35→        'User-Agent': 'PAI-Hook/1.0'
    36→      },
    37→      body: JSON.stringify(event),
    38→    });
    39→
    40→    if (!response.ok) {
    41→      // Log error but don't throw - dashboard may be offline
    42→      console.error(`Observability server returned status: ${response.status}`);
    43→    }
    44→  } catch (error) {
    45→    // Fail silently - dashboard may not be running
    46→    // This is intentional - hooks should never fail due to observability issues
    47→    // Uncomment below for debugging:
    48→    // console.error('Failed to send event to observability:', error);
    49→  }
    50→}
