   236→function findRunningVoiceServers(): number[] {
   237→  try {
   238→    if (IS_WINDOWS) {
   239→      // Windows: Use netstat to find process using port
   240→      const result = execSync(`netstat -ano | findstr :${VOICE_SERVER_PORT}`, {
   241→        encoding: 'utf-8',
   242→        stdio: ['pipe', 'pipe', 'pipe']
   243→      });
   244→      const pids: number[] = [];
   245→      const lines = result.trim().split('\n');
   246→      for (const line of lines) {
   247→        const parts = line.trim().split(/\s+/);
   248→        const pid = parseInt(parts[parts.length - 1]);
   249→        if (!isNaN(pid)) {
   250→          pids.push(pid);
   251→        }
   252→      }
   253→      return [...new Set(pids)]; // Unique PIDs
   254→    } else {
   255→      // Unix: Use lsof
   256→      const result = execSync(`lsof -ti:${VOICE_SERVER_PORT}`, {
   257→        encoding: 'utf-8',
   258→        stdio: ['pipe', 'pipe', 'pipe']
   259→      });
   260→      return result.trim().split('\n').map(s => parseInt(s.trim())).filter(n => !isNaN(n));
   261→    }
   262→  } catch (e) {
   263→    return [];
   264→  }
   265→}
   266→
   267→function killVoiceServers(): void {
   268→  const pids = findRunningVoiceServers();
   269→  if (pids.length > 0) {
   270→    printInfo(`Killing ${pids.length} existing voice server(s)`);
   271→    for (const pid of pids) {
   272→      try {
   273→        if (IS_WINDOWS) {
   274→          execSync(`taskkill /F /PID ${pid}`, { stdio: 'pipe' });
   275→        } else {
   276→          execSync(`kill -9 ${pid}`, { stdio: 'pipe' });
   277→        }
   278→        printSuccess(`Killed process ${pid}`);
   279→      } catch (e) { /* ignore */ }
   280→    }
   281→  }
   282→}
   283→
   284→async function startVoiceServer(): Promise<boolean> {
   285→  if (IS_WINDOWS) {
   286→    const startScript = join(VOICE_SERVER_DIR, 'start.ps1');
   287→    if (!existsSync(startScript)) {
   288→      printWarning('Voice server start.ps1 script not found');
   289→      return false;
   290→    }
   291→  } else {
   292→    const startScript = join(VOICE_SERVER_DIR, 'start.sh');
   293→    if (!existsSync(startScript)) {
   294→      printWarning('Voice server start.sh script not found');
   295→      return false;
   296→    }
   297→  }
   298→
   299→  killVoiceServers();
   300→
   301→  try {
   302→    let command: string;
   303→    let args: string[];
   304→
   305→    if (IS_WINDOWS) {
   306→      command = 'powershell';
   307→      args = ['-ExecutionPolicy', 'Bypass', '-File', join(VOICE_SERVER_DIR, 'start.ps1')];
   308→    } else {
   309→      command = 'bash';
   310→      args = [join(VOICE_SERVER_DIR, 'start.sh')];
   311→    }
   312→
   313→    const child = spawn(command, args, {
   314→      detached: true,
   315→      stdio: 'ignore',
   316→      cwd: VOICE_SERVER_DIR,
   317→      shell: true
   318→    });
   319→    child.unref();
   320→
   321→    await new Promise(resolve => setTimeout(resolve, 2000));
   322→
   323→    if (findRunningVoiceServers().length > 0) {
   324→      printSuccess('Voice server started');
   325→      return true;
   326→    } else {
   327→      printWarning('Voice server may not have started');
   328→      return false;
   329→    }
   330→  } catch (err: any) {
   331→    printError(`Failed to start voice server: ${err.message}`);
   332→    return false;
   333→  }
   334→}
